{"version":3,"sources":["pages/data/dashboard.uvue"],"sourcesContent":["<template>\r\n  <view class=\"page\">\r\n    <view class=\"page-bg\">\r\n      <image class=\"page-bg-img\" src=\"/static/images/micro-habit-page-bg.png\" mode=\"aspectFill\"></image>\r\n    </view>\r\n    <scroll-view class=\"scroll-area\" scroll-y=\"true\">\r\n      <view class=\"section\">\r\n        <view class=\"section-header\">\r\n          <text class=\"section-title\">今日数据</text>\r\n        </view>\r\n        <view class=\"section-body\">\r\n          <StatusIndicator title=\"护眼\" :percent=\"eyeScore\" :status=\"eyeStatus\" />\r\n          <StatusIndicator title=\"体态\" :percent=\"postureScore\" :status=\"postureStatus\" />\r\n          <StatusIndicator title=\"活力\" :percent=\"vitalityScore\" :status=\"vitalityStatus\" />\r\n\r\n          <view class=\"guard-box\">\r\n            <text class=\"guard-label\">今日完成</text>\r\n            <text class=\"guard-value\">{{ guardCount }} 次</text>\r\n            <text class=\"guard-sub\">习惯渗透度 {{ penetrationText }}</text>\r\n          </view>\r\n\r\n          <view class=\"chart-container\">\r\n            <text class=\"chart-label\">各时段完成次数（相对高度）</text>\r\n            <BarChart\r\n              :labels=\"hourlyLabels\"\r\n              :values=\"hourlyValues\"\r\n              :height=\"300\"\r\n              barColor=\"#4CAF50\"\r\n            />\r\n          </view>\r\n\r\n          <view class=\"list-section\" v-if=\"detailCount > 0\">\r\n            <text class=\"chart-label\">今日完成记录</text>\r\n            <view class=\"detail-item\" v-for=\"(item, idx) in todayDetails\" :key=\"idx\">\r\n              <view class=\"detail-left\">\r\n                <text class=\"detail-name\">{{ item.name }}</text>\r\n                <text class=\"detail-type\">{{ item.type }}</text>\r\n              </view>\r\n              <view class=\"detail-right\">\r\n                <text class=\"detail-duration\">{{ item.durationSec }}s</text>\r\n                <text class=\"detail-time\">{{ item.time }}</text>\r\n              </view>\r\n            </view>\r\n          </view>\r\n          <view class=\"empty-hint\" v-if=\"detailCount < 1\">\r\n            <text class=\"empty-text\">今日暂无完成记录</text>\r\n          </view>\r\n        </view>\r\n      </view>\r\n\r\n      <view class=\"section\">\r\n        <view class=\"section-header\">\r\n          <text class=\"section-title\">本周趋势</text>\r\n        </view>\r\n        <view class=\"section-body\">\r\n          <view class=\"chart-container\">\r\n            <LineChart\r\n              :series-values=\"weekTrendValues\"\r\n              :series-names=\"weekTrendNames\"\r\n              :series-colors=\"weekTrendColors\"\r\n              :point-labels=\"weekTrendLabels\"\r\n              :height=\"360\"\r\n              title=\"本周完成次数趋势（左右可拖动）\"\r\n            />\r\n          </view>\r\n        </view>\r\n      </view>\r\n\r\n      <view class=\"section\">\r\n        <view class=\"section-header\">\r\n          <text class=\"section-title\">打卡热力图（近4周）</text>\r\n        </view>\r\n        <view class=\"section-body\">\r\n          <view class=\"chart-container\">\r\n            <HeatmapCalendar\r\n              :dates=\"heatmapDates\"\r\n              :counts=\"heatmapCounts\"\r\n              :height=\"320\"\r\n            />\r\n          </view>\r\n          <view class=\"heatmap-legend\">\r\n            <text class=\"legend-text\">点击格子查看当天详情</text>\r\n          </view>\r\n        </view>\r\n      </view>\r\n\r\n      <view class=\"section\">\r\n        <view class=\"section-header\" @tap=\"toggleWeekly\">\r\n          <text class=\"section-title\">每周健康报告</text>\r\n          <text class=\"section-toggle\">{{ weeklyToggleText }}</text>\r\n        </view>\r\n        <view class=\"section-body\" v-if=\"weeklyShow\">\r\n          <view class=\"loading-box\" v-if=\"weeklyReportLoading\">\r\n            <text class=\"loading-text\">生成中...</text>\r\n          </view>\r\n          <view class=\"report-box\" v-if=\"weeklyLoaded && !weeklyReportLoading\">\r\n            <view class=\"report-stats\">\r\n              <view class=\"stat-item\">\r\n                <text class=\"stat-val\">{{ wkTotalCompleted }}</text>\r\n                <text class=\"stat-label\">次完成</text>\r\n              </view>\r\n              <view class=\"stat-item\">\r\n                <text class=\"stat-val\">{{ wkAvgGuard }}</text>\r\n                <text class=\"stat-label\">日均守护</text>\r\n              </view>\r\n              <view class=\"stat-item\">\r\n                <text class=\"stat-val\">{{ wkBestDay }}</text>\r\n                <text class=\"stat-label\">最佳日次</text>\r\n              </view>\r\n            </view>\r\n            <text class=\"report-body\">{{ wkBody }}</text>\r\n          </view>\r\n          <view class=\"empty-hint\" v-if=\"!weeklyLoaded && !weeklyReportLoading\">\r\n            <text class=\"empty-text\">点击下方按钮生成周报</text>\r\n            <view class=\"refresh-btn\" @tap=\"refreshWeek\">\r\n              <text class=\"refresh-text\">生成周报</text>\r\n            </view>\r\n          </view>\r\n        </view>\r\n      </view>\r\n\r\n      <view class=\"bottom-spacer\" />\r\n    </scroll-view>\r\n  </view>\r\n</template>\r\n\r\n<script setup lang=\"uts\">\r\nimport StatusIndicator from '../../components/StatusIndicator.uvue'\r\nimport BarChart from '../../components/BarChart.uvue'\r\nimport LineChart from '../../components/LineChart.uvue'\r\nimport HeatmapCalendar from '../../components/HeatmapCalendar.uvue'\r\nimport { useAppStore } from '../../stores/appStore'\r\nimport { getHourlyData, getWeeklyTrend, getTodayDetail, ActionDetail, LineSeries } from '../../services/ScoreCalculator'\r\nimport { today } from '../../utils/TimeUtils'\r\nimport { BarItem } from '../../database/ActionLogDao'\r\nimport { DailyCount } from '../../models/DailyCount'\r\n\r\nconst store = useAppStore()\r\n\r\nconst eyeScore = computed<number>(() : number => store.eyeScore.value)\r\nconst eyeStatus = computed<string>(() : string => store.eyeStatus.value)\r\nconst postureScore = computed<number>(() : number => store.postureScore.value)\r\nconst postureStatus = computed<string>(() : string => store.postureStatus.value)\r\nconst vitalityScore = computed<number>(() : number => store.vitalityScore.value)\r\nconst vitalityStatus = computed<string>(() : string => store.vitalityStatus.value)\r\nconst guardCount = computed<number>(() : number => store.guardCount.value)\r\nfunction getPenetrationText(): string {\r\n  const p = store.penetration.value\r\n  return '' + Math.round(p * 10) / 10\r\n}\r\nconst penetrationText = computed<string>(getPenetrationText)\r\nconst heatmapData = computed<DailyCount[]>(() => store.heatmapData.value)\r\n\r\nconst hourlyLabels = ref<string[]>([])\r\nconst hourlyValues = ref<number[]>([])\r\n\r\nconst weekTrendValues = ref<number[][]>([])\r\nconst weekTrendNames = ref<string[]>([])\r\nconst weekTrendColors = ref<string[]>([])\r\nconst weekTrendLabels = ref<string[]>([])\r\n\r\nconst heatmapDates = ref<string[]>([])\r\nconst heatmapCounts = ref<number[]>([])\r\n\r\nconst weeklyShow = ref<boolean>(false)\r\nconst weeklyToggleText = computed<string>(() : string => weeklyShow.value ? '▼' : '▶')\r\n\r\nconst weeklyLoaded = computed<boolean>(() : boolean => store.weeklyReport.value != null)\r\nconst weeklyReportLoading = computed<boolean>(() : boolean => store.weeklyReportLoading.value)\r\n\r\nfunction getWkBody(): string {\r\n  const r = store.weeklyReport.value\r\n  return r != null ? r.bodyMarkdown : ''\r\n}\r\nfunction getWkTotalCompleted(): number {\r\n  const r = store.weeklyReport.value\r\n  return r != null ? r.stats.totalCompleted : 0\r\n}\r\nfunction getWkAvgGuard(): number {\r\n  const r = store.weeklyReport.value\r\n  return r != null ? r.stats.avgGuardMinutes : 0\r\n}\r\nfunction getWkBestDay(): number {\r\n  const r = store.weeklyReport.value\r\n  return r != null ? r.stats.bestDayCount : 0\r\n}\r\nconst wkBody = computed<string>(getWkBody)\r\nconst wkTotalCompleted = computed<number>(getWkTotalCompleted)\r\nconst wkAvgGuard = computed<number>(getWkAvgGuard)\r\nconst wkBestDay = computed<number>(getWkBestDay)\r\n\r\nconst todayDetails = ref<ActionDetail[]>([])\r\nconst detailCount = computed<number>(() : number => todayDetails.value.length)\r\n\r\nfunction loadData(): void {\r\n  const date = today()\r\n  const hourly = getHourlyData(date)\r\n  const hLabels: string[] = []\r\n  const hValues: number[] = []\r\n  for (let i = 0; i < hourly.length; i++) {\r\n    hLabels.push(hourly[i].label)\r\n    hValues.push(hourly[i].value)\r\n  }\r\n  hourlyLabels.value = hLabels\r\n  hourlyValues.value = hValues\r\n\r\n  const trend = getWeeklyTrend()\r\n  if (trend.length > 0) {\r\n    const first = trend[0]\r\n    if (first != null) {\r\n      weekTrendNames.value = [first.name]\r\n      weekTrendColors.value = [first.color]\r\n      const v: number[] = []\r\n      const labels: string[] = []\r\n      for (let i = 0; i < first.points.length; i++) {\r\n        labels.push(first.points[i].label)\r\n        v.push(first.points[i].value)\r\n      }\r\n      weekTrendLabels.value = labels\r\n      weekTrendValues.value = [v]\r\n    } else {\r\n      weekTrendNames.value = []\r\n      weekTrendColors.value = []\r\n      weekTrendLabels.value = []\r\n      weekTrendValues.value = []\r\n    }\r\n  } else {\r\n    weekTrendNames.value = []\r\n    weekTrendColors.value = []\r\n    weekTrendLabels.value = []\r\n    weekTrendValues.value = []\r\n  }\r\n\r\n  const heatmap = store.heatmapData.value\r\n  const dArr: string[] = []\r\n  const cArr: number[] = []\r\n  for (let i = 0; i < heatmap.length; i++) {\r\n    dArr.push(heatmap[i].date)\r\n    cArr.push(heatmap[i].count)\r\n  }\r\n  heatmapDates.value = dArr\r\n  heatmapCounts.value = cArr\r\n\r\n  todayDetails.value = getTodayDetail()\r\n}\r\n\r\nfunction toggleWeekly(): void {\r\n  weeklyShow.value = !weeklyShow.value\r\n}\r\n\r\nfunction refreshWeek(): void {\r\n  weeklyShow.value = true\r\n  store.refreshWeeklyReport()\r\n}\r\n\r\nonPageShow(() => {\r\n  store.refreshHomeData()\r\n  loadData()\r\n})\r\n</script>\r\n\r\n<style scoped>\r\n.page {\r\n  flex: 1;\r\n  background-color: transparent;\r\n  position: relative;\r\n  overflow: hidden;\r\n}\r\n.page-bg {\r\n  position: absolute;\r\n  left: 0;\r\n  top: 0;\r\n  width: 100%;\r\n  height: 100%;\r\n  z-index: 0;\r\n}\r\n.page-bg-img {\r\n  width: 100%;\r\n  height: 100%;\r\n}\r\n.scroll-area {\r\n  flex: 1;\r\n  position: relative;\r\n  z-index: 1;\r\n}\r\n.section {\r\n  background-color: #FFFFFF;\r\n  margin: 8px;\r\n  border-radius: 12px;\r\n  overflow: hidden;\r\n}\r\n.section-header {\r\n  flex-direction: row;\r\n  justify-content: space-between;\r\n  align-items: center;\r\n  padding: 14px 16px;\r\n  border-bottom: 1px solid #F0F0F0;\r\n}\r\n.section-title {\r\n  font-size: 16px;\r\n  font-weight: bold;\r\n  color: #2C3E50;\r\n}\r\n.section-toggle {\r\n  font-size: 12px;\r\n  color: #95A5A6;\r\n}\r\n.section-body {\r\n  padding: 12px 0;\r\n}\r\n.guard-box {\r\n  align-items: center;\r\n  padding: 16px;\r\n  margin: 8px 16px;\r\n  background-color: #EBF5FB;\r\n  border-radius: 12px;\r\n}\r\n.guard-label {\r\n  font-size: 13px;\r\n  color: #7F8C8D;\r\n}\r\n.guard-value {\r\n  font-size: 28px;\r\n  font-weight: bold;\r\n  color: #2980B9;\r\n  margin-top: 4px;\r\n}\r\n.guard-sub {\r\n  font-size: 12px;\r\n  color: #95A5A6;\r\n  margin-top: 4px;\r\n}\r\n.chart-container {\r\n  padding: 8px 4px;\r\n}\r\n.chart-label {\r\n  font-size: 13px;\r\n  font-weight: bold;\r\n  color: #7F8C8D;\r\n  padding-left: 16px;\r\n  margin-bottom: 4px;\r\n}\r\n.list-section {\r\n  padding: 0 16px;\r\n}\r\n.detail-item {\r\n  flex-direction: row;\r\n  justify-content: space-between;\r\n  align-items: center;\r\n  padding: 10px 0;\r\n  border-bottom: 1px solid #F0F0F0;\r\n}\r\n.detail-left {\r\n  flex-direction: column;\r\n}\r\n.detail-name {\r\n  font-size: 14px;\r\n  color: #2C3E50;\r\n}\r\n.detail-type {\r\n  font-size: 11px;\r\n  color: #95A5A6;\r\n  margin-top: 2px;\r\n}\r\n.detail-right {\r\n  flex-direction: column;\r\n  align-items: flex-end;\r\n}\r\n.detail-duration {\r\n  font-size: 14px;\r\n  color: #27AE60;\r\n  font-weight: bold;\r\n}\r\n.detail-time {\r\n  font-size: 11px;\r\n  color: #95A5A6;\r\n  margin-top: 2px;\r\n}\r\n.heatmap-legend {\r\n  align-items: center;\r\n  padding: 4px 0 12px;\r\n}\r\n.legend-text {\r\n  font-size: 12px;\r\n  color: #BDC3C7;\r\n}\r\n.empty-hint {\r\n  align-items: center;\r\n  padding: 24px;\r\n}\r\n.empty-text {\r\n  font-size: 13px;\r\n  color: #BDC3C7;\r\n}\r\n.loading-box {\r\n  align-items: center;\r\n  padding: 24px;\r\n}\r\n.loading-text {\r\n  font-size: 13px;\r\n  color: #95A5A6;\r\n}\r\n.report-box {\r\n  padding: 16px;\r\n}\r\n.report-title {\r\n  font-size: 17px;\r\n  font-weight: bold;\r\n  color: #2C3E50;\r\n  margin-bottom: 8px;\r\n}\r\n.report-highlight {\r\n  font-size: 14px;\r\n  color: #34495E;\r\n  line-height: 1.5;\r\n}\r\n.report-body {\r\n  font-size: 14px;\r\n  color: #2C3E50;\r\n  line-height: 1.6;\r\n  white-space: pre-wrap;\r\n  margin-top: 8px;\r\n}\r\n.report-stats {\r\n  flex-direction: row;\r\n  justify-content: space-around;\r\n  margin: 16px 0;\r\n  padding: 12px;\r\n  background-color: #F5F6FA;\r\n  border-radius: 8px;\r\n}\r\n.stat-item {\r\n  align-items: center;\r\n}\r\n.stat-val {\r\n  font-size: 20px;\r\n  font-weight: bold;\r\n  color: #2980B9;\r\n}\r\n.stat-label {\r\n  font-size: 11px;\r\n  color: #95A5A6;\r\n  margin-top: 2px;\r\n}\r\n.report-improve {\r\n  font-size: 13px;\r\n  color: #7F8C8D;\r\n  line-height: 1.5;\r\n  margin-top: 8px;\r\n}\r\n.refresh-btn {\r\n  margin-top: 12px;\r\n  padding: 10px 24px;\r\n  background-color: #2980B9;\r\n  border-radius: 8px;\r\n}\r\n.refresh-text {\r\n  color: #FFFFFF;\r\n  font-size: 14px;\r\n}\r\n.bottom-spacer {\r\n  height: 80px;\r\n}\r\n</style>\r\n"],"names":[],"mappings":";;;;;;;;;;;;;;;;;;;;;;YA