{"version":3,"sources":["pages/data/dashboard.uvue"],"sourcesContent":["<template>\n  <view class=\"page\">\n    <view class=\"page-bg\">\n      <image class=\"page-bg-img\" src=\"/static/images/micro-habit-page-bg.png\" mode=\"aspectFill\"></image>\n    </view>\n    <view class=\"bg-glow glow-purple\"></view>\n    <view class=\"bg-glow glow-blue\"></view>\n    <view class=\"bg-glow glow-pink\"></view>\n    <scroll-view class=\"scroll-area\" scroll-y=\"true\">\n      <view class=\"dashboard-hero\">\n        <view class=\"dashboard-hero-copy\">\n          <text class=\"dashboard-kicker\">微憩星球</text>\n          <text class=\"dashboard-title\">健康轨迹</text>\n          <text class=\"dashboard-subtitle\">每一次短暂停顿，都会在小星球上留下一点光。</text>\n        </view>\n        <view class=\"dashboard-planet\">\n          <view class=\"dashboard-orbit\"></view>\n          <text class=\"dashboard-planet-text\">✦</text>\n        </view>\n      </view>\n\n      <view class=\"section\">\n        <view class=\"section-header\">\n          <text class=\"section-title\">今日概览</text>\n        </view>\n        <view class=\"section-body\">\n          <StatusIndicator title=\"护眼\" :percent=\"eyeScore\" :status=\"eyeStatus\" />\n          <StatusIndicator title=\"体态\" :percent=\"postureScore\" :status=\"postureStatus\" />\n          <StatusIndicator title=\"活力\" :percent=\"vitalityScore\" :status=\"vitalityStatus\" />\n\n          <view class=\"guard-box\">\n            <text class=\"guard-label\">今日完成</text>\n            <text class=\"guard-value\">{{ guardCount }} 次</text>\n            <text class=\"guard-sub\">习惯渗透度 {{ penetrationText }}</text>\n          </view>\n\n          <view class=\"chart-container\">\n            <text class=\"chart-label\">今天哪些时刻点亮了星球</text>\n            <BarChart\n              :labels=\"hourlyLabels\"\n              :values=\"hourlyValues\"\n              :height=\"220\"\n              barColor=\"#CBB8FF\"\n            />\n          </view>\n\n          <view class=\"list-section\" v-if=\"detailCount > 0\">\n            <text class=\"chart-label\">今日完成记录</text>\n            <view class=\"detail-item\" v-for=\"(item, idx) in todayDetails\" :key=\"idx\">\n              <view class=\"detail-left\">\n                <text class=\"detail-name\">{{ item.name }}</text>\n                <text class=\"detail-type\">{{ formatDetailType(item.type) }}</text>\n              </view>\n              <view class=\"detail-right\">\n                <text class=\"detail-duration\">{{ item.durationSec }}秒</text>\n                <text class=\"detail-time\">{{ item.time }}</text>\n              </view>\n            </view>\n          </view>\n          <view class=\"empty-hint\" v-if=\"detailCount < 1\">\n            <text class=\"empty-text\">完成更多微动作后，这里会出现你的健康轨迹</text>\n          </view>\n        </view>\n      </view>\n\n      <view class=\"section\">\n        <view class=\"section-header\" @tap=\"toggleWeekly\">\n          <text class=\"section-title\">本周星球报告</text>\n          <text class=\"section-toggle\">{{ weeklyToggleText }}</text>\n        </view>\n        <view class=\"section-body\" v-if=\"weeklyShow\">\n          <view class=\"loading-box\" v-if=\"weeklyReportLoading\">\n            <text class=\"loading-text\">生成中</text>\n          </view>\n          <view class=\"report-box\" v-if=\"weeklyLoaded && !weeklyReportLoading\">\n            <view class=\"report-stats\">\n              <view class=\"stat-item\">\n                <text class=\"stat-val\">{{ wkTotalCompleted }}</text>\n                <text class=\"stat-label\">次完成</text>\n              </view>\n              <view class=\"stat-item\">\n                <text class=\"stat-val\">{{ wkAvgGuard }}</text>\n                <text class=\"stat-label\">日均守护</text>\n              </view>\n              <view class=\"stat-item\">\n                <text class=\"stat-val\">{{ wkBestDay }}</text>\n                <text class=\"stat-label\">最佳日次</text>\n              </view>\n            </view>\n            <text class=\"report-body\">{{ wkBody }}</text>\n          </view>\n          <view class=\"empty-hint\" v-if=\"!weeklyLoaded && !weeklyReportLoading\">\n            <text class=\"empty-text\">点击下方按钮生成周报</text>\n            <view class=\"refresh-btn\" @tap=\"refreshWeek\">\n              <text class=\"refresh-text\">生成周报</text>\n            </view>\n          </view>\n        </view>\n      </view>\n\n      <view class=\"section\">\n        <view class=\"section-header\">\n          <text class=\"section-title\">三颗星球趋势</text>\n        </view>\n        <view class=\"section-body\">\n          <view class=\"chart-container\">\n            <LineChart\n              :series-values=\"weekTrendValues\"\n              :series-names=\"weekTrendNames\"\n              :series-colors=\"weekTrendColors\"\n              :point-labels=\"weekTrendLabels\"\n              :height=\"360\"\n              title=\"本周完成次数趋势（左右可拖动）\"\n            />\n          </view>\n        </view>\n      </view>\n\n      <view class=\"section\">\n        <view class=\"section-header\">\n          <text class=\"section-title\">星球点亮记录</text>\n        </view>\n        <view class=\"section-body\">\n          <view class=\"chart-container\">\n            <HeatmapCalendar\n              :dates=\"heatmapDates\"\n              :counts=\"heatmapCounts\"\n              :height=\"320\"\n            />\n          </view>\n          <view class=\"heatmap-legend\">\n            <text class=\"legend-text\">点击格子查看当天详情</text>\n          </view>\n        </view>\n      </view>\n\n      <view class=\"bottom-spacer\" />\n    </scroll-view>\n  </view>\n</template>\n\n<script setup lang=\"uts\">\nimport StatusIndicator from '../../components/StatusIndicator.uvue'\nimport BarChart from '../../components/BarChart.uvue'\nimport LineChart from '../../components/LineChart.uvue'\nimport HeatmapCalendar from '../../components/HeatmapCalendar.uvue'\nimport { useAppStore } from '../../stores/appStore'\nimport { getHourlyData, getWeeklyTrend, getTodayDetail, ActionDetail, LineSeries } from '../../services/ScoreCalculator'\nimport { today } from '../../utils/TimeUtils'\nimport { BarItem } from '../../database/ActionLogDao'\nimport { DailyCount } from '../../models/DailyCount'\n\nconst store = useAppStore()\n\nconst eyeScore = computed<number>(() : number => store.eyeScore.value)\nconst eyeStatus = computed<string>(() : string => store.eyeStatus.value)\nconst postureScore = computed<number>(() : number => store.postureScore.value)\nconst postureStatus = computed<string>(() : string => store.postureStatus.value)\nconst vitalityScore = computed<number>(() : number => store.vitalityScore.value)\nconst vitalityStatus = computed<string>(() : string => store.vitalityStatus.value)\nconst guardCount = computed<number>(() : number => store.guardCount.value)\nfunction getPenetrationText(): string {\n  const p = store.penetration.value\n  return '' + Math.round(p * 10) / 10\n}\nconst penetrationText = computed<string>(getPenetrationText)\nconst heatmapData = computed<DailyCount[]>(() => store.heatmapData.value)\n\nconst hourlyLabels = ref<string[]>([])\nconst hourlyValues = ref<number[]>([])\n\nconst weekTrendValues = ref<number[][]>([])\nconst weekTrendNames = ref<string[]>([])\nconst weekTrendColors = ref<string[]>([])\nconst weekTrendLabels = ref<string[]>([])\n\nconst heatmapDates = ref<string[]>([])\nconst heatmapCounts = ref<number[]>([])\n\nconst weeklyShow = ref<boolean>(false)\nconst weeklyToggleText = computed<string>(() : string => weeklyShow.value ? '▼' : '▶')\n\nconst weeklyLoaded = computed<boolean>(() : boolean => store.weeklyReport.value != null)\nconst weeklyReportLoading = computed<boolean>(() : boolean => store.weeklyReportLoading.value)\n\nfunction getWkBody(): string {\n  const r = store.weeklyReport.value\n  return r != null ? r.bodyMarkdown : ''\n}\nfunction getWkTotalCompleted(): number {\n  const r = store.weeklyReport.value\n  return r != null ? r.stats.totalCompleted : 0\n}\nfunction getWkAvgGuard(): number {\n  const r = store.weeklyReport.value\n  return r != null ? r.stats.avgGuardMinutes : 0\n}\nfunction getWkBestDay(): number {\n  const r = store.weeklyReport.value\n  return r != null ? r.stats.bestDayCount : 0\n}\nconst wkBody = computed<string>(getWkBody)\nconst wkTotalCompleted = computed<number>(getWkTotalCompleted)\nconst wkAvgGuard = computed<number>(getWkAvgGuard)\nconst wkBestDay = computed<number>(getWkBestDay)\n\nconst todayDetails = ref<ActionDetail[]>([])\nconst detailCount = computed<number>(() : number => todayDetails.value.length)\n\nfunction formatDetailType(t: string): string {\n  if (t === 'eye') return '护眼'\n  if (t === 'posture') return '体态'\n  if (t === 'vitality') return '活力'\n  if (t === 'breath') return '呼吸'\n  if (t === 'neck_shoulder') return '肩颈'\n  if (t === 'core') return '核心'\n  if (t === 'lower_body') return '下肢'\n  return t\n}\n\nfunction loadData(): void {\n  const date = today()\n  const hourly = getHourlyData(date)\n  const hLabels: string[] = []\n  const hValues: number[] = []\n  for (let i = 0; i < hourly.length; i++) {\n    hLabels.push(hourly[i].label)\n    hValues.push(hourly[i].value)\n  }\n  hourlyLabels.value = hLabels\n  hourlyValues.value = hValues\n\n  const trend = getWeeklyTrend()\n  if (trend.length > 0) {\n    const first = trend[0]\n    if (first != null) {\n      weekTrendNames.value = [first.name]\n      weekTrendColors.value = [first.color]\n      const v: number[] = []\n      const labels: string[] = []\n      for (let i = 0; i < first.points.length; i++) {\n        labels.push(first.points[i].label)\n        v.push(first.points[i].value)\n      }\n      weekTrendLabels.value = labels\n      weekTrendValues.value = [v]\n    } else {\n      weekTrendNames.value = []\n      weekTrendColors.value = []\n      weekTrendLabels.value = []\n      weekTrendValues.value = []\n    }\n  } else {\n    weekTrendNames.value = []\n    weekTrendColors.value = []\n    weekTrendLabels.value = []\n    weekTrendValues.value = []\n  }\n\n  const heatmap = store.heatmapData.value\n  const dArr: string[] = []\n  const cArr: number[] = []\n  for (let i = 0; i < heatmap.length; i++) {\n    dArr.push(heatmap[i].date)\n    cArr.push(heatmap[i].count)\n  }\n  heatmapDates.value = dArr\n  heatmapCounts.value = cArr\n\n  todayDetails.value = getTodayDetail()\n}\n\nfunction toggleWeekly(): void {\n  weeklyShow.value = !weeklyShow.value\n}\n\nfunction refreshWeek(): void {\n  weeklyShow.value = true\n  store.refreshWeeklyReport()\n}\n\nonPageShow(() => {\n  store.refreshHomeData()\n  loadData()\n})\n</script>\n\n<style scoped>\n.page {\n  flex: 1;\n  background-color: #162038;\n  position: relative;\n  overflow: hidden;\n}\n.page-bg { position: absolute; left: 0; top: 0; width: 100%; height: 100%; z-index: 0; }\n.page-bg-img { width: 100%; height: 100%; }\n.scroll-area {\n  flex: 1;\n  position: relative;\n  z-index: 1;\n}\n.bg-glow {\n  position: absolute;\n  border-radius: 999px;\n  z-index: 0;\n}\n.glow-purple {\n  width: 210px;\n  height: 210px;\n  left: -82px;\n  top: -54px;\n  background-color: #776B97;\n  opacity: 0.5;\n}\n.glow-blue {\n  width: 168px;\n  height: 168px;\n  right: -60px;\n  top: 104px;\n  background-color: #C2E0EE;\n  opacity: 0.24;\n}\n.glow-pink {\n  width: 178px;\n  height: 178px;\n  left: 42px;\n  bottom: 88px;\n  background-color: #C68DC0;\n  opacity: 0.18;\n}\n.sky-star {\n  position: absolute;\n  width: 3px;\n  height: 3px;\n  border-radius: 2px;\n  background-color: rgba(255, 255, 255, 0.74);\n  z-index: 0;\n}\n.star-a { left: 36px; top: 88px; }\n.star-b { left: 118px; top: 144px; width: 4px; height: 4px; border-radius: 2px; }\n.star-c { right: 52px; top: 116px; }\n.star-d { right: 26px; top: 310px; width: 5px; height: 5px; border-radius: 3px; }\n.star-e { left: 54px; top: 520px; }\n.star-f { right: 86px; top: 420px; width: 4px; height: 4px; border-radius: 2px; }\n.star-g { left: 138px; top: 610px; }\n.star-h { right: 36px; top: 720px; width: 4px; height: 4px; border-radius: 2px; }\n.star-i { left: 76px; top: 214px; width: 2px; height: 2px; border-radius: 1px; }\n.star-j { right: 148px; top: 276px; width: 3px; height: 3px; border-radius: 2px; }\n.star-k { left: 178px; top: 392px; width: 2px; height: 2px; border-radius: 1px; }\n.star-l { right: 64px; top: 560px; width: 3px; height: 3px; border-radius: 2px; }\n\n.dashboard-hero,\n.settings-hero,\n.planet-note,\n.section,\n.settings-section,\n.guard-box,\n.chart-container,\n.report-stats,\n.tag-card,\n.header-block,\n.filter-row,\n.empty-block {\n  background-color: rgba(29, 25, 62, 0.82);\n  background-image: linear-gradient(135deg, rgba(48, 42, 94, 0.92) 0%, rgba(84, 65, 124, 0.72) 56%, rgba(198, 141, 192, 0.18) 100%);\n  border-width: 1px;\n  border-color: rgba(219, 200, 237, 0.18);\n  border-style: solid;\n  box-shadow: 0 18px 42px rgba(5, 6, 20, 0.28);\n}\n.dashboard-hero,\n.settings-hero { margin: 22px 14px 12px 14px; padding: 22px 18px; border-radius: 28px; flex-direction: row; align-items: center; }\n.dashboard-hero-copy,\n.settings-hero-copy { flex: 1; flex-direction: column; padding-right: 12px; }\n.dashboard-kicker,\n.settings-kicker,\n.section-toggle,\n.setting-value,\n.rule-priority,\n.rule-source,\n.detail-duration,\n.guard-value,\n.stat-val { color: #DBC8ED; }\n.dashboard-kicker,\n.settings-kicker { font-size: 13px; font-weight: bold; margin-bottom: 8px; }\n.dashboard-title,\n.settings-title,\n.section-title,\n.setting-label,\n.planet-note-title,\n.detail-name,\n.report-body,\n.report-title,\n.header-title,\n.tag-label { color: #FFFFFF; }\n.dashboard-title,\n.settings-title { font-size: 28px; font-weight: bold; line-height: 34px; }\n.dashboard-subtitle,\n.settings-subtitle,\n.planet-note-text,\n.setting-hint,\n.guard-label,\n.guard-sub,\n.chart-label,\n.legend-text,\n.empty-text,\n.loading-text,\n.detail-type,\n.detail-time,\n.stat-label,\n.rule-cond,\n.rule-time,\n.header-desc,\n.tag-pkg,\n.tag-uses,\n.empty-hint { color: rgba(255, 255, 255, 0.72); }\n.dashboard-subtitle,\n.settings-subtitle { font-size: 13px; line-height: 20px; margin-top: 8px; }\n.dashboard-planet,\n.settings-planet { position: relative; width: 86px; height: 86px; border-radius: 43px; background-color: rgba(219, 200, 237, 0.18); align-items: center; justify-content: center; }\n.dashboard-orbit,\n.settings-orbit { position: absolute; width: 96px; height: 34px; border-radius: 48px; border-width: 2px; border-color: rgba(219, 200, 237, 0.38); border-style: solid; transform: rotate(-20deg); }\n.dashboard-planet-text,\n.settings-planet-text { color: #DBC8ED; font-size: 34px; }\n.planet-note { margin: 0 14px 12px 14px; padding: 16px 18px; border-radius: 24px; }\n.planet-note-title { font-size: 16px; font-weight: bold; margin-bottom: 6px; }\n.planet-note-text { font-size: 12px; line-height: 19px; }\n.section,\n.settings-section { margin: 12px 14px; border-radius: 24px; overflow: hidden; }\n.section-header { flex-direction: row; justify-content: space-between; align-items: center; padding: 16px 18px 8px 18px; }\n.section-title { font-size: 18px; font-weight: bold; padding: 0; }\n.section-body { padding: 8px 0 14px 0; }\n.guard-box { margin: 8px 16px 12px 16px; padding: 18px; border-radius: 22px; align-items: center; }\n.guard-value { font-size: 28px; font-weight: bold; margin-top: 4px; }\n.chart-container { margin: 10px 16px 0 16px; padding: 14px 0 6px 0; border-radius: 22px; }\n.chart-label { padding-left: 14px; margin-bottom: 0; font-size: 13px; font-weight: bold; }\n.list-section { padding: 0 16px; }\n.detail-item { flex-direction: row; justify-content: space-between; align-items: center; padding: 10px 0; border-bottom-width: 1px; border-bottom-color: rgba(219, 200, 237, 0.16); border-bottom-style: solid; }\n.detail-left,\n.detail-right,\n.setting-left { flex-direction: column; }\n.detail-right { align-items: flex-end; }\n.detail-name { font-size: 14px; }\n.detail-type,\n.detail-time { font-size: 11px; margin-top: 2px; }\n.detail-duration { font-size: 14px; font-weight: bold; }\n.heatmap-legend,\n.empty-hint,\n.loading-box { align-items: center; padding: 20px; }\n.report-box { padding: 16px; }\n.report-body { font-size: 14px; line-height: 22px; white-space: pre-wrap; margin-top: 8px; }\n.report-stats { flex-direction: row; justify-content: space-around; margin: 10px 16px; padding: 12px; border-radius: 18px; }\n.stat-item { align-items: center; }\n.stat-val { font-size: 20px; font-weight: bold; }\n.refresh-btn { margin-top: 12px; padding: 10px 24px; background-color: #DBC8ED; border-radius: 18px; }\n.refresh-text { color: #161A33; font-size: 14px; font-weight: bold; }\n.setting-item { flex-direction: row; justify-content: space-between; align-items: center; padding: 15px 18px; border-bottom-width: 1px; border-bottom-color: rgba(219, 200, 237, 0.16); border-bottom-style: solid; }\n.setting-left { flex: 1; }\n.setting-label { font-size: 15px; font-weight: bold; }\n.setting-hint { font-size: 12px; line-height: 18px; margin-top: 4px; }\n.setting-value { font-size: 14px; font-weight: bold; }\n.empty-rules { align-items: center; padding: 24px 16px 28px 16px; }\n.rule-card { padding: 14px 18px; border-bottom-width: 1px; border-bottom-color: rgba(219, 200, 237, 0.16); border-bottom-style: solid; }\n.rule-row1,\n.rule-row2 { flex-direction: row; align-items: center; margin-top: 4px; }\n.rule-type,\n.rule-trigger { font-size: 11px; border-radius: 12px; padding: 4px 8px; margin-right: 6px; }\n.rule-type { color: #FFFFFF; background-color: rgba(219, 200, 237, 0.18); font-weight: bold; }\n.rule-trigger { color: rgba(255, 255, 255, 0.72); background-color: rgba(194, 224, 238, 0.12); }\n.rule-priority { font-size: 11px; margin-left: auto; }\n.rule-source,\n.rule-cond { font-size: 11px; }\n.rule-source { margin-right: 8px; }\n.rule-cond { flex: 1; }\n.rule-row3 { flex-direction: row; justify-content: space-between; margin-top: 4px; }\n.rule-time { font-size: 10px; }\n.header-block { margin: 22px 14px 12px 14px; padding: 20px 18px; border-radius: 28px; flex-direction: column; }\n.header-title { font-size: 22px; font-weight: bold; margin-bottom: 8px; }\n.header-desc { font-size: 12px; line-height: 19px; }\n.filter-row { flex-direction: row; flex-wrap: wrap; margin: 0 14px 12px 14px; padding: 12px 12px 4px 12px; border-radius: 22px; }\n.filter-chip { padding: 6px 12px; background-color: rgba(255, 255, 255, 0.1); border-radius: 14px; margin-right: 6px; margin-bottom: 8px; }\n.filter-chip-active { background-color: #DBC8ED; }\n.filter-chip-text { font-size: 12px; color: #FFFFFF; }\n.empty-block { margin: 12px 14px; padding: 50px 20px; border-radius: 24px; align-items: center; }\n.tag-list { padding: 0 14px 18px 14px; }\n.tag-card { border-radius: 22px; padding: 14px; margin-bottom: 10px; flex-direction: row; }\n.tag-card-left { flex: 1; flex-direction: column; }\n.tag-card-right { flex-direction: column; align-items: flex-end; margin-left: 10px; }\n.tag-label { font-size: 14px; font-weight: bold; margin-bottom: 3px; }\n.tag-pkg { font-size: 11px; margin-bottom: 7px; }\n.tag-source-row { flex-direction: row; align-items: center; }\n.tag-source { font-size: 10px; padding: 3px 7px; border-radius: 8px; margin-right: 6px; }\n.tag-source-llm { background-color: rgba(194, 224, 238, 0.14); color: #C2E0EE; }\n.tag-source-user { background-color: rgba(143, 240, 195, 0.12); color: #8FF0C3; }\n.tag-source-pending { background-color: rgba(219, 200, 237, 0.14); color: #DBC8ED; }\n.cat-picker { flex-direction: row; align-items: center; background-color: rgba(255, 255, 255, 0.1); padding: 5px 10px; border-radius: 12px; margin-bottom: 6px; }\n.cat-picker-text { font-size: 12px; color: #FFFFFF; margin-right: 4px; }\n.cat-picker-arrow,\n.lock-text { color: rgba(255, 255, 255, 0.68); }\n.lock-text-on { color: #DBC8ED; font-weight: bold; }\n.bottom-spacer { height: 132px; }\n</style>\n"],"names":[],"mappings":";;;;;;;;;;;;;;;;;;;;;;YAwJA,IAAM,QAAQ;YAEd,IAAM,WAAW,SAAS,MAAM,EAAE,OAAK,MAAM;uBAAI